/* --- Exception handling --- */

/* Stack-based rescue/ensure adapters for proper nesting support.
 * CRuby callbacks have signature VALUE(*)(VALUE) while mruby has
 * mrb_value(*)(mrb_state*, mrb_value). We use a stack since
 * begin/rescue blocks can be nested. */

typedef mrb_value (*konpeito_callback_fn)(mrb_state *, mrb_value);

#define KONPEITO_MAX_RESCUE_STACK 32

/* Rescue stack */
static struct {
    konpeito_callback_fn body;
    mrb_value data1;
    konpeito_callback_fn handler;
    mrb_value data2;
} rescue_stack[KONPEITO_MAX_RESCUE_STACK];
static int rescue_depth = 0;

static mrb_value rescue_body_wrapper(mrb_state *mrb, mrb_value data) {
    (void)data;
    int idx = rescue_depth - 1;
    return rescue_stack[idx].body(mrb, rescue_stack[idx].data1);
}

static mrb_value rescue_handler_wrapper(mrb_state *mrb, mrb_value data) {
    (void)data;
    int idx = rescue_depth - 1;
    return rescue_stack[idx].handler(mrb, rescue_stack[idx].data2);
}

/* CRuby: VALUE rb_rescue2(VALUE (*body)(VALUE), VALUE data1,
 *                         VALUE (*handler)(VALUE, VALUE), VALUE data2, ...) */
mrb_value rb_rescue2(void *body, mrb_value data1, void *handler, mrb_value data2, ...) {
    if (rescue_depth >= KONPEITO_MAX_RESCUE_STACK) {
        mrb_raise(konpeito_mrb_state, E_RUNTIME_ERROR, "rescue nesting too deep");
        return mrb_nil_value();
    }
    rescue_stack[rescue_depth].body = (konpeito_callback_fn)body;
    rescue_stack[rescue_depth].data1 = data1;
    rescue_stack[rescue_depth].handler = (konpeito_callback_fn)handler;
    rescue_stack[rescue_depth].data2 = data2;
    rescue_depth++;
    mrb_value result = mrb_rescue(konpeito_mrb_state,
                                   rescue_body_wrapper, mrb_nil_value(),
                                   rescue_handler_wrapper, mrb_nil_value());
    rescue_depth--;
    return result;
}

/* Ensure stack */
static struct {
    konpeito_callback_fn body;
    mrb_value data1;
    konpeito_callback_fn cleanup;
    mrb_value data2;
} ensure_stack[KONPEITO_MAX_RESCUE_STACK];
static int ensure_depth = 0;

static mrb_value ensure_body_wrapper(mrb_state *mrb, mrb_value data) {
    (void)data;
    int idx = ensure_depth - 1;
    return ensure_stack[idx].body(mrb, ensure_stack[idx].data1);
}

static mrb_value ensure_cleanup_wrapper(mrb_state *mrb, mrb_value data) {
    (void)data;
    int idx = ensure_depth - 1;
    return ensure_stack[idx].cleanup(mrb, ensure_stack[idx].data2);
}

/* CRuby: VALUE rb_ensure(VALUE (*body)(VALUE), VALUE data1,
 *                        VALUE (*ensure_fn)(VALUE), VALUE data2) */
mrb_value rb_ensure(void *body, mrb_value data1, void *cleanup, mrb_value data2) {
    if (ensure_depth >= KONPEITO_MAX_RESCUE_STACK) {
        mrb_raise(konpeito_mrb_state, E_RUNTIME_ERROR, "ensure nesting too deep");
        return mrb_nil_value();
    }
    ensure_stack[ensure_depth].body = (konpeito_callback_fn)body;
    ensure_stack[ensure_depth].data1 = data1;
    ensure_stack[ensure_depth].cleanup = (konpeito_callback_fn)cleanup;
    ensure_stack[ensure_depth].data2 = data2;
    ensure_depth++;
    mrb_value result = mrb_ensure(konpeito_mrb_state,
                                   ensure_body_wrapper, mrb_nil_value(),
                                   ensure_cleanup_wrapper, mrb_nil_value());
    ensure_depth--;
    return result;
}

/* CRuby: VALUE rb_protect(VALUE (*func)(VALUE), VALUE arg, int *state) */
mrb_value rb_protect(void *func, mrb_value arg, int *state) {
    /* mruby doesn't have rb_protect directly. Use mrb_rescue as approximation. */
    typedef mrb_value (*protect_fn)(mrb_state *, mrb_value);
    protect_fn fn = (protect_fn)func;
    mrb_bool error;
    mrb_value result = mrb_protect(konpeito_mrb_state, (mrb_func_t)fn, arg, &error);
    if (state) *state = error ? 1 : 0;
    return result;
}

/* CRuby: VALUE rb_errinfo(void) */
mrb_value rb_errinfo(void) {
    if (konpeito_mrb_state->exc) {
        return mrb_obj_value(konpeito_mrb_state->exc);
    }
    return mrb_nil_value();
}

/* CRuby: void rb_set_errinfo(VALUE err) */
void rb_set_errinfo(mrb_value err) {
    if (mrb_nil_p(err)) {
        konpeito_mrb_state->exc = NULL;
    } else {
        konpeito_mrb_state->exc = mrb_obj_ptr(err);
    }
}

/* CRuby: void rb_jump_tag(int state) */
void rb_jump_tag(int state) {
    (void)state;
    /* In mruby, there's no direct equivalent. Raise a runtime error. */
    mrb_raise(konpeito_mrb_state, E_RUNTIME_ERROR, "rb_jump_tag called");
}

/* CRuby: void rb_raise(VALUE exc_class, const char *fmt, ...) */
void rb_raise(mrb_value exc_class, const char *fmt, ...) {
    char buf[1024];
    va_list args;
    va_start(args, fmt);
    vsnprintf(buf, sizeof(buf), fmt, args);
    va_end(args);
    struct RClass *cls = mrb_class_ptr(exc_class);
    mrb_raise(konpeito_mrb_state, cls, buf);
}

/* --- Exception class globals --- */
/* In CRuby these are extern VALUE globals. In mruby we provide them
 * as variables initialized at startup. */

mrb_value rb_eStandardError;
mrb_value rb_eRuntimeError;
mrb_value rb_eArgError;  /* CRuby name for ArgumentError */

/* --- Object class global --- */
mrb_value rb_cObject;

/* --- Core class globals --- */
mrb_value rb_cInteger;
mrb_value rb_cFloat;
mrb_value rb_cString;
mrb_value rb_cSymbol;
mrb_value rb_cArray;
mrb_value rb_cHash;
mrb_value rb_cNilClass;
mrb_value rb_cTrueClass;
mrb_value rb_cFalseClass;

/* Thread/Mutex/Queue class globals (stubs) */
mrb_value rb_cThread;
mrb_value rb_cMutex;
mrb_value rb_cQueue;

/* --- Constant access --- */

/* CRuby: VALUE rb_const_get(VALUE module, ID name) */
mrb_value rb_const_get(mrb_value module, mrb_sym name) {
    return mrb_const_get(konpeito_mrb_state, module, name);
}

/* CRuby: void rb_const_set(VALUE module, ID name, VALUE value) */
void rb_const_set(mrb_value module, mrb_sym name, mrb_value value) {
    mrb_const_set(konpeito_mrb_state, module, name, value);
}

/* --- Range --- */

/* CRuby: VALUE rb_range_new(VALUE beg, VALUE end, int exclude_end) */
mrb_value rb_range_new(mrb_value beg, mrb_value end, int exclude_end) {
    return mrb_range_new(konpeito_mrb_state, beg, end, (mrb_bool)exclude_end);
}

/* --- Global variables --- */

/* CRuby: VALUE rb_gv_get(const char *name) */
mrb_value rb_gv_get(const char *name) {
    mrb_sym sym = mrb_intern_cstr(konpeito_mrb_state, name);
    return mrb_gv_get(konpeito_mrb_state, sym);
}

/* CRuby: VALUE rb_gv_set(const char *name, VALUE val) */
mrb_value rb_gv_set(const char *name, mrb_value val) {
    mrb_sym sym = mrb_intern_cstr(konpeito_mrb_state, name);
    mrb_gv_set(konpeito_mrb_state, sym, val);
    return val;
}

/* --- Super call --- */

/* CRuby: VALUE rb_call_super(int argc, const VALUE *argv) */
mrb_value rb_call_super(int argc, const mrb_value *argv) {
    /* mruby doesn't expose a C API for super calls from cfuncs.
     * The Konpeito compiler handles super by directly calling the parent
     * class method by its mangled name. This stub is a fallback. */
    (void)argc;
    (void)argv;
    mrb_raise(konpeito_mrb_state, E_RUNTIME_ERROR,
              "super call from C function is not supported in mruby target");
    return mrb_nil_value();
}

/* --- Type checking --- */

/* CRuby: VALUE rb_obj_is_kind_of(VALUE obj, VALUE klass) */
mrb_value rb_obj_is_kind_of(mrb_value obj, mrb_value klass) {
    struct RClass *cls = mrb_class_ptr(klass);
    mrb_bool result = mrb_obj_is_kind_of(konpeito_mrb_state, obj, cls);
    return result ? mrb_true_value() : mrb_false_value();
}

/* CRuby: VALUE rb_path2class(const char *path) */
mrb_value rb_path2class(const char *path) {
    struct RClass *cls = mrb_class_get(konpeito_mrb_state, path);
    return mrb_obj_value(cls);
}

/* --- Require (stub) --- */

/* CRuby: void rb_require(const char *feature) */
void rb_require(const char *feature) {
    /* mruby doesn't support dynamic require — all code is compiled in.
     * This is a no-op for stdlib requires. */
    (void)feature;
}

/* --- GC marking --- */

/* CRuby: void rb_gc_mark(VALUE obj) */
void rb_gc_mark(mrb_value obj) {
    mrb_gc_mark_value(konpeito_mrb_state, obj);
}

/* ================================================================
 * Initialization function — called from main() after mrb_open()
 * Sets up all the global class/exception variables.
 * ================================================================ */

void konpeito_mruby_init_globals(void) {
    mrb_state *mrb = konpeito_mrb_state;
    if (!mrb) return;

    /* Exception classes */
    rb_eStandardError = mrb_obj_value(E_STANDARD_ERROR);
    rb_eRuntimeError  = mrb_obj_value(E_RUNTIME_ERROR);
    rb_eArgError      = mrb_obj_value(E_ARGUMENT_ERROR);

    /* Object class */
    rb_cObject = mrb_obj_value(mrb->object_class);

    /* Core classes */
    rb_cInteger   = mrb_obj_value(mrb_class_get(mrb, "Integer"));
    rb_cFloat     = mrb_obj_value(mrb_class_get(mrb, "Float"));
    rb_cString    = mrb_obj_value(mrb_class_get(mrb, "String"));
    rb_cSymbol    = mrb_obj_value(mrb_class_get(mrb, "Symbol"));
    rb_cArray     = mrb_obj_value(mrb_class_get(mrb, "Array"));
    rb_cHash      = mrb_obj_value(mrb_class_get(mrb, "Hash"));
    rb_cNilClass  = mrb_obj_value(mrb_class_get(mrb, "NilClass"));
    rb_cTrueClass = mrb_obj_value(mrb_class_get(mrb, "TrueClass"));
    rb_cFalseClass = mrb_obj_value(mrb_class_get(mrb, "FalseClass"));

    /* Thread/Mutex/Queue stubs */
    rb_cThread = mrb_nil_value();
    rb_cMutex  = mrb_nil_value();
    rb_cQueue  = mrb_nil_value();
}

